// ~30% fire rate — skip most ticks to create random interval effect
if (Math.random() > 0.3) {
  return [];
}
return [{ json: { proceed: true } }];

const row = $input.first().json;
const failures = parseInt(row.failure_count) || 0;
const ok = parseInt(row.ok_count) || 0;
const total = parseInt(row.total_count) || 0;
const avgTtfb = parseInt(row.avg_ttfb) || 0;
const lastSeen = row.last_seen ? new Date(row.last_seen).toLocaleTimeString('en-AU', { hour: '2-digit', minute: '2-digit', timeZone: 'Australia/Melbourne' }) : 'n/a';
const surgeCount = parseInt(row.surge_count) || 0;

if (total === 0) {
  return [{ json: { message: '💀 **Monitor pipeline is down**\n\nNo results in the last 30 minutes.\nhttps://github.com/DeveloperAlly/gamerslab/actions' } }];
}

const recent = row.recent || [];
const byRegion = {};
for (const r of recent) {
  if (!byRegion[r.region]) byRegion[r.region] = { ok: 0, fail: 0, ttfbs: [] };
  r.ok ? byRegion[r.region].ok++ : byRegion[r.region].fail++;
  if (r.ttfb) byRegion[r.region].ttfbs.push(r.ttfb);
}

const regionLines = Object.entries(byRegion).map(([reg, d]) => {
  const tot = d.ok + d.fail;
  const pct = tot ? Math.round(d.ok / tot * 100) : 0;
  const avg = d.ttfbs.length ? Math.round(d.ttfbs.reduce((a,b)=>a+b,0)/d.ttfbs.length) : 0;
  const icon = pct === 100 ? '🟢' : pct >= 80 ? '🟡' : '🔴';
  return `${icon} ${reg} — ${pct}% · ${avg}ms`;
}).join('\n');

const statusIcon = failures === 0 ? '✅' : failures < 3 ? '⚠️' : '🚨';
const failLine = failures > 0 ? `\n⚠️ **${failures} failures detected**` : '';

return [{ json: { message: `${statusIcon} **GamersLab Monitor — 30 min report**\n**${ok}/${total} checks passed** · avg ${avgTtfb}ms · last run ${lastSeen}${surgeCount > 0 ? ` · ${surgeCount} surge runs` : ''}${failLine}\n\n${regionLines}` } }];

const { url, name } = $input.first().json.body;
if (!url) throw new Error('url is required');
return [{ json: { url, name: name || url } }];

const { scheduledAt, label } = $input.first().json.body;
if (!scheduledAt) throw new Error('scheduledAt is required (ISO 8601)');

const fireAt = new Date(scheduledAt);
const now = new Date();
const delayMs = fireAt.getTime() - now.getTime();

if (delayMs < 0) throw new Error('scheduledAt must be in the future');
if (delayMs > 15 * 24 * 60 * 60 * 1000) throw new Error('scheduledAt must be within 15 days');

return [{ json: {
  scheduledAt: fireAt.toISOString(),
  label: label || 'Scheduled surge',
  delayMs,
  delayMinutes: Math.round(delayMs / 60000)
} }];

